INSERT INTO Artifact
VALUES (3000039, 368, 'The Daughters of Edward Darley Boit','This painting was painted by Sargent in the family''s Paris Apartment. Notice the vases insert into the painting displayed next to the artwork','https://upload.wikimedia.org/wikipedia/commons/thumb/9/96/The_Daughters_of_Edward_Darley_Boit%2C_John_Singer_Sargent%2C_1882_%28unfree_frame_crop%29.jpg/960px-The_Daughters_of_Edward_Darley_Boit%2C_John_Singer_Sargent%2C_1882_%28unfree_frame_crop%29.jpg','pristine', 'realism', 1882, 'Oil on canvas', 3324, 823),
    (3000040, NULL, 'Set of 2, blue-and-white Japanese Vases', NULL,'https://cdn.shopify.com/s/files/1/1358/1837/files/unnamed_6.jpg?v=1642192203','good', NULL, NULL, 'Porcelain', 3324, 823),
    (3000042, 352, 'Woman in the Garden','This painting was completed en plein air, and the woman in the portait is actually Monet''s cousin''s wife.','https://upload.wikimedia.org/wikipedia/commons/thumb/0/0e/Claude_Monet_022.jpg/960px-Claude_Monet_022.jpg','fair', 'Impressionism', 1866, 'Oil on canvas', 3324, 293),
    (3007529, 349, 'The Death of Dido', 'The Death of Dido by Leonardo da Vinci is an artwork in the modern style', 'https://images.metmuseum.org/CRDImages/dp/original/DP807559.jpg', 'good', 'modern', 1663, 'Pen and brown ink, brush and brown wash, over black chalk; framing lines in pen and brown ink on mount', 3330, 703),
    (3008869, 349, 'Virgin and Child Enthroned with Saint Anthony Abbot, Saint Peter, Saint Paul, Saint Julian the Hospitaler, Saint Roch, and Saint Mary Magdalen?', 'Virgin and Child Enthroned with Saint Anthony Abbot, Saint Peter, Saint Paul, Saint Julian the Hospitaler, Saint Roch, and Saint Mary Magdalen? by Leonardo da Vinci is an artwork in the renaissance style', 'https://images.metmuseum.org/CRDImages/dp/original/DP811060.jpg', 'pristine', 'renaissance', 1523, 'Pen and brown ink, highlighted with white gouache, on brownish paper', 3358, 703),
